import React from 'react';
import {
  LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend,
} from 'recharts';
import { useTheme } from '../ThemeContext';

const data = [
  { month: 'Jan', hours: 160, salary: 5200 },
  { month: 'Feb', hours: 152, salary: 5000 },
  { month: 'Mar', hours: 168, salary: 5400 },
  { month: 'Apr', hours: 170, salary: 5600 },
  { month: 'May', hours: 155, salary: 5100 },
  { month: 'Jun', hours: 163, salary: 5300 },
];

export function MonthlyAnalytics() {
  const { theme } = useTheme();
  const grid    = theme === 'dark' ? '#1e293b' : '#f1f5f9';
  const textMuted = theme === 'dark' ? '#64748b' : '#94a3b8';
  const cardBg  = theme === 'dark' ? '#1e293b' : '#fff';
  const border  = theme === 'dark' ? '#334155' : '#e2e8f0';
  const text    = theme === 'dark' ? '#f1f5f9' : '#0f172a';

  return (
    <div className="bg-dash-card border border-dash-border rounded-xl p-5 flex flex-col gap-4 transition-colors duration-200">
      <div className="flex items-center justify-between">
        <h3 className="text-dash-text" style={{ fontSize: '14px', fontWeight: 600 }}>Monthly Analytics</h3>
        <span className="text-xs text-dash-text-muted">Last 6 months</span>
      </div>

      <ResponsiveContainer width="100%" height={200}>
        <LineChart data={data} margin={{ top: 5, right: 10, left: -20, bottom: 0 }}>
          <CartesianGrid strokeDasharray="3 3" stroke={grid} />
          <XAxis dataKey="month" tick={{ fontSize: 11, fill: textMuted }} axisLine={false} tickLine={false} />
          <YAxis yAxisId="left" tick={{ fontSize: 11, fill: textMuted }} axisLine={false} tickLine={false} />
          <YAxis yAxisId="right" orientation="right" tick={{ fontSize: 11, fill: textMuted }} axisLine={false} tickLine={false} />
          <Tooltip
            contentStyle={{ background: cardBg, border: `1px solid ${border}`, borderRadius: '8px', fontSize: '12px', color: text }}
          />
          <Legend wrapperStyle={{ fontSize: '12px', color: textMuted }} />
          <Line yAxisId="left" type="monotone" dataKey="hours" stroke="#6366f1" strokeWidth={2} dot={false} name="Hours worked" />
          <Line yAxisId="right" type="monotone" dataKey="salary" stroke="#10b981" strokeWidth={2} dot={false} name="Net salary ($)" />
        </LineChart>
      </ResponsiveContainer>
    </div>
  );
}
